public class FraudDetector extends KeyedProcessFunction<Long, Tx, Alert> {
    private ValueState<Long> lastTimeState;

    public void open(Configuration c) {
        lastTimeState = getRuntimeContext().getState(
            new ValueStateDescriptor<>('last-time', Long.class));
    }
}

// Setting maxParallelism is CRITICAL!
env.setMaxParallelism(256);  // immutable после старта

// Если parallelism=4, maxParallelism=256:
// subtask 0: kg 0-63, subtask 1: 64-127, ...
// При rescale до 8: каждый subtask получит 32 kg

// Old (sync):
Long v = state.value();

// New (async):
state.asyncValue().thenAccept(v -> {
    if (v == null) state.asyncUpdate(1);
    else state.asyncUpdate(v + 1);
});

WatermarkStrategy.<Event>forBoundedOutOfOrderness(Duration.ofSeconds(20))
    .withTimestampAssigner((e, ts) -> e.getEventTime())  // ← event time
    .withIdleness(Duration.ofMinutes(1));

// Bounded out-of-orderness — самая частая стратегия
.forBoundedOutOfOrderness(Duration.ofSeconds(20))
// watermark = maxObservedTs - 20s

// Идемпотентно для idle partitions:
.withIdleness(Duration.ofMinutes(1))

.forBoundedOutOfOrderness(Duration.ofSeconds(20))
.withWatermarkAlignment(
    'multi-source-group',
    Duration.ofSeconds(20),  // max-allowed-drift
    Duration.ofSeconds(1)    // update-interval
);

